## Included Documentation

<doc path="csharp/claude-api.md">
<h1>Claude API — C#</h1>
<blockquote>
<p><strong>Note:</strong> The C# SDK is the official Anthropic SDK for C#. Tool use is supported via the Messages API. A class-annotation-based tool runner is not available; use raw tool definitions with JSON schema. The SDK also supports Microsoft.Extensions.AI IChatClient integration with function invocation.</p>
</blockquote>
<h2>Installation</h2>
<pre><code class="language-bash">dotnet add package Anthropic
</code></pre>
<h2>Client Initialization</h2>
<pre><code class="language-csharp">using Anthropic;

// Default (uses ANTHROPIC_API_KEY env var)
AnthropicClient client = new();

// Explicit API key (use environment variables — never hardcode keys)
AnthropicClient client = new() {
    ApiKey = [REDACTED:SECRET](&quot;ANTHROPIC_API_KEY&quot;)
};
</code></pre>
<hr />
<h2>Basic Message Request</h2>
<pre><code class="language-csharp">using Anthropic.Models.Messages;

var parameters = new MessageCreateParams
{
    Model = Model.ClaudeOpus4_6,
    MaxTokens = 1024,
    Messages = [new() { Role = Role.User, Content = &quot;What is the capital of France?&quot; }]
};
var message = await client.Messages.Create(parameters);
Console.WriteLine(message);
</code></pre>
<hr />
<h2>Streaming</h2>
<pre><code class="language-csharp">using Anthropic.Models.Messages;

var parameters = new MessageCreateParams
{
    Model = Model.ClaudeOpus4_6,
    MaxTokens = 1024,
    Messages = [new() { Role = Role.User, Content = &quot;Write a haiku&quot; }]
};

await foreach (RawMessageStreamEvent streamEvent in client.Messages.CreateStreaming(parameters))
{
    if (streamEvent.TryPickContentBlockDelta(out var delta) &amp;&amp;
        delta.Delta.TryPickText(out var text))
    {
        Console.Write(text.Text);
    }
}
</code></pre>
